import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest'
import handleDelete from '@/path/to/handleDelete'
import * as noteService from '@/services/noteService'

vi.mock('@/services/noteService', () => ({
  deleteNoteById: vi.fn()
}))

describe('handleDelete', () => {
  const mockEvent = { target: { dataset: { id: '123' } } }

  beforeEach(() => {
    vi.clearAllMocks()
  })

  it('should handle happy path when element has a valid id', async () => {
    ;(noteService.deleteNoteById as vi.Mock).mockResolvedValueOnce(true)
    await handleDelete(mockEvent as any)
    expect(noteService.deleteNoteById).toHaveBeenCalledWith('123')
  })

  it('should handle edge case when event target is missing dataset id', async () => {
    const eventWithoutId = { target: { dataset: {} } }
    await handleDelete(eventWithoutId as any)
    expect(noteService.deleteNoteById).not.toHaveBeenCalled()
  })

  it('should handle null/empty event', async () => {
    await handleDelete(null as any)
    await handleDelete(undefined as any)
    await handleDelete({} as any)
    expect(noteService.deleteNoteById).not.toHaveBeenCalled()
  })
})